'use strict';

const W = 1080;
const H = 1350;
const COLORS = { orange: '#ff6f00', cream: '#fff6ea', blue: '#005c78', ink: '#111111' };
const LOGO_DATA = 'data:image/png;base64,';
const STORAGE_KEY = 'cdb-studio-mobile-v01';
const SVG_NS = 'http://www.w3.org/2000/svg';

const $ = (id) => document.getElementById(id);
const canvas = $('canvas');
const stage = $('stage');
const measureCanvas = document.createElement('canvas');
const measureCtx = measureCanvas.getContext('2d');

let selected = 'title';
let currentIndex = 0;
let activeTab = 'content';
let saveTimer = null;
let toastTimer = null;
let history = [];
let historyIndex = -1;
const historyImagePool = new Map();
const pointers = new Map();
let gesture = null;

function uid() {
  return Math.random().toString(36).slice(2, 9);
}

function clamp(v, min, max) {
  return Math.max(min, Math.min(max, v));
}

function esc(value = '') {
  return String(value).replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&apos;'}[c]));
}

function deepClone(value) {
  return JSON.parse(JSON.stringify(value));
}

function transformDefaults() {
  return { dx: 0, dy: 0, scale: 1 };
}

function textDefaults(overrides = {}) {
  return {
    text: '', font: 'Anybody', size: 96, weight: 850, width: 90,
    lineHeight: 0.92, color: COLORS.cream, ...transformDefaults(), ...overrides
  };
}

function defaultSlide(type = 'cover') {
  const common = {
    id: uid(), type,
    image: { src: '', ...transformDefaults() },
    logo: { ...transformDefaults() },
    title: textDefaults({ text: '5 FILM CHE MERITAVANO MOLTO DI PIÙ' }),
    subtitle: textDefaults({ text: 'Una selezione firmata Critici da Bar', size: 44, weight: 650, width: 100, lineHeight: 1.08 })
  };
  if (type === 'body') {
    common.title = textDefaults({ text: 'UN FILM CHE NON HA AVUTO IL SUCCESSO CHE MERITAVA', size: 67, color: COLORS.blue, width: 94 });
    common.subtitle = textDefaults({ text: 'Qui puoi inserire il testo della slide. Il layout mantiene automaticamente margini e leggibilità.', size: 38, weight: 520, color: COLORS.ink, lineHeight: 1.16, width: 100 });
  } else if (type === 'question') {
    common.title = textDefaults({ text: 'E VOI CHE NE PENSATE?', size: 104, color: COLORS.blue, width: 88 });
    common.subtitle = textDefaults({ text: 'Diteci la vostra nei commenti', size: 48, weight: 650, color: COLORS.cream, width: 100 });
  } else if (type === 'final') {
    common.title = textDefaults({ text: 'SALVA IL POST E SEGUICI PER ALTRI CONSIGLI', size: 92, color: COLORS.cream, width: 88 });
    common.subtitle = textDefaults({ text: '@criticidabar', size: 42, weight: 720, color: COLORS.cream, width: 100 });
  }
  return common;
}

function newProject() {
  return { version: '0.2.0', name: 'Nuovo carosello', slides: [defaultSlide('cover'), defaultSlide('body'), defaultSlide('question')] };
}

function normalizeText(value, fallback) {
  return { ...fallback, ...(value || {}) };
}

function normalizeSlide(slide) {
  const base = defaultSlide(slide?.type || 'cover');
  return {
    ...base, ...slide,
    image: { ...base.image, ...(slide?.image || {}) },
    logo: { ...base.logo, ...(slide?.logo || {}) },
    title: normalizeText(slide?.title, base.title),
    subtitle: normalizeText(slide?.subtitle, base.subtitle)
  };
}

function openProjectDb() {
  return new Promise((resolve, reject) => {
    const request = indexedDB.open('cdb-studio', 1);
    request.onupgradeneeded = () => {
      if (!request.result.objectStoreNames.contains('projects')) request.result.createObjectStore('projects');
    };
    request.onsuccess = () => resolve(request.result);
    request.onerror = () => reject(request.error);
  });
}

async function dbGet(key) {
  const db = await openProjectDb();
  return new Promise((resolve, reject) => {
    const tx = db.transaction('projects', 'readonly');
    const request = tx.objectStore('projects').get(key);
    request.onsuccess = () => resolve(request.result);
    request.onerror = () => reject(request.error);
  });
}

async function dbPut(key, value) {
  const db = await openProjectDb();
  return new Promise((resolve, reject) => {
    const tx = db.transaction('projects', 'readwrite');
    tx.objectStore('projects').put(value, key);
    tx.oncomplete = () => resolve();
    tx.onerror = () => reject(tx.error);
  });
}

function migrateLegacyProject(parsed) {
  if (!parsed?.client?.st || !Array.isArray(parsed.slides)) return parsed;
  const legacyState = parsed.client.st;
  const order = parsed.client.order || parsed.slides.map((_, i) => i);
  const slides = order.map((oldIndex) => {
    const source = parsed.slides[oldIndex] || {};
    const old = legacyState[String(oldIndex)] || legacyState[oldIndex] || {};
    let type = source.slideType === 'cover' ? 'cover' : source.slideType === 'end' ? 'final' : 'body';
    if (/CHE NE PENSATE|DOMANDA|COMMENT/i.test(source.mainText || '')) type = 'question';
    const slide = defaultSlide(type);
    slide.title.text = source.mainText || source.postLabel || source.postTitle || slide.title.text;
    slide.subtitle.text = source.subText || '';
    if (old.imgT) slide.image = { ...slide.image, dx: old.imgT.dx || 0, dy: old.imgT.dy || 0, scale: old.imgT.s || 1 };
    if (old.logoT) slide.logo = { ...slide.logo, dx: old.logoT.dx || 0, dy: old.logoT.dy || 0, scale: old.logoT.s || 1 };
    if (old.txtT) {
      slide.title.dx = old.txtT.dx || 0; slide.title.dy = old.txtT.dy || 0; slide.title.scale = old.txtT.s || 1;
      slide.subtitle.dx = old.txtT.dx || 0; slide.subtitle.dy = old.txtT.dy || 0; slide.subtitle.scale = old.txtT.s || 1;
    }
    return slide;
  });
  return { version: '0.2.0', name: parsed.slides[0]?.postTitle || 'Progetto importato', slides };
}

async function loadProject() {
  try {
    let parsed = await dbGet('current');
    if (!parsed) {
      const legacyLocal = localStorage.getItem(STORAGE_KEY);
      if (legacyLocal) parsed = JSON.parse(legacyLocal);
    }
    if (!parsed) return newProject();
    parsed = migrateLegacyProject(parsed);
    parsed.slides = Array.isArray(parsed.slides) && parsed.slides.length ? parsed.slides.map(normalizeSlide) : [defaultSlide()];
    return parsed;
  } catch (error) {
    console.warn('Progetto locale non leggibile', error);
    return newProject();
  }
}

let project = newProject();

function currentSlide() {
  return project.slides[currentIndex];
}

function currentElement() {
  return currentSlide()?.[selected] || null;
}

function templateLayout(type) {
  if (type === 'body') {
    return {
      image: { x: 0, y: 0, w: W, h: 610, cx: 540, cy: 305 },
      title: { x: 72, y: 738, maxWidth: 936, align: 'left', cx: 540, cy: 825 },
      subtitle: { x: 72, y: 952, maxWidth: 936, align: 'left', cx: 540, cy: 1060 },
      logo: { x: 735, y: 1190, w: 270, h: 192, cx: 870, cy: 1286 }
    };
  }
  if (type === 'question') {
    return {
      image: { x: 0, y: 0, w: W, h: H, cx: 540, cy: 675 },
      title: { x: 540, y: 545, maxWidth: 790, align: 'center', cx: 540, cy: 610 },
      subtitle: { x: 540, y: 895, maxWidth: 820, align: 'center', cx: 540, cy: 920 },
      logo: { x: 362, y: 1080, w: 356, h: 254, cx: 540, cy: 1207 }
    };
  }
  if (type === 'final') {
    return {
      image: { x: 0, y: 0, w: W, h: H, cx: 540, cy: 675 },
      title: { x: 86, y: 430, maxWidth: 890, align: 'left', cx: 540, cy: 610 },
      subtitle: { x: 88, y: 965, maxWidth: 700, align: 'left', cx: 440, cy: 990 },
      logo: { x: 600, y: 1015, w: 385, h: 274, cx: 792, cy: 1152 }
    };
  }
  return {
    image: { x: 0, y: 0, w: W, h: H, cx: 540, cy: 675 },
    title: { x: 76, y: 420, maxWidth: 925, align: 'left', cx: 540, cy: 610 },
    subtitle: { x: 82, y: 947, maxWidth: 680, align: 'left', cx: 420, cy: 980 },
    logo: { x: 652, y: 1048, w: 330, h: 235, cx: 817, cy: 1165 }
  };
}

function fontCss(text) {
  return `font-family:${JSON.stringify(text.font)},sans-serif;font-size:${text.size}px;font-weight:${text.weight};`;
}

function wrapLines(text, style, maxWidth) {
  const rawParagraphs = String(text || '').split(/\n/);
  const result = [];
  const widthFactor = (style.width || 100) / 100;
  const threshold = maxWidth / Math.max(widthFactor, 0.01);
  measureCtx.font = `${style.weight || 400} ${style.size || 60}px "${style.font || 'Anybody'}"`;
  for (const paragraph of rawParagraphs) {
    if (!paragraph.trim()) { result.push(''); continue; }
    const words = paragraph.trim().split(/\s+/);
    let line = '';
    for (const word of words) {
      const candidate = line ? `${line} ${word}` : word;
      if (line && measureCtx.measureText(candidate).width > threshold) {
        result.push(line);
        line = word;
      } else {
        line = candidate;
      }
    }
    if (line) result.push(line);
  }
  return result.length ? result : [''];
}

function transformAttr(state, cx, cy) {
  return `translate(${state.dx || 0} ${state.dy || 0}) translate(${cx} ${cy}) scale(${state.scale || 1}) translate(${-cx} ${-cy})`;
}

function textSvg(key, style, layout) {
  const lines = wrapLines(style.text, style, layout.maxWidth);
  const anchor = layout.align === 'center' ? 'middle' : layout.align === 'right' ? 'end' : 'start';
  const tspans = lines.map((line, index) => `<tspan x="${layout.x}" dy="${index === 0 ? 0 : style.size * style.lineHeight}">${esc(line)}</tspan>`).join('');
  return `<g data-element="${key}" data-cx="${layout.cx}" data-cy="${layout.cy}" transform="${transformAttr(style, layout.cx, layout.cy)}">
    <g transform="translate(${layout.x} 0) scale(${(style.width || 100) / 100} 1) translate(${-layout.x} 0)">
      <text x="${layout.x}" y="${layout.y}" text-anchor="${anchor}" dominant-baseline="alphabetic" fill="${style.color}" style="${fontCss(style)}">${tspans}</text>
    </g>
  </g>`;
}

function imageSvg(slide, layout, clipId) {
  const t = slide.image;
  if (!t.src) return '';
  return `<g data-element="image" data-cx="${layout.cx}" data-cy="${layout.cy}" transform="${transformAttr(t, layout.cx, layout.cy)}">
    <image href="${esc(t.src)}" x="${layout.x}" y="${layout.y}" width="${layout.w}" height="${layout.h}" preserveAspectRatio="xMidYMid slice" clip-path="url(#${clipId})" />
  </g>`;
}

function logoSvg(slide, layout) {
  return `<g data-element="logo" data-cx="${layout.cx}" data-cy="${layout.cy}" transform="${transformAttr(slide.logo, layout.cx, layout.cy)}">
    <image href="${LOGO_DATA}" x="${layout.x}" y="${layout.y}" width="${layout.w}" height="${layout.h}" preserveAspectRatio="xMidYMid meet" />
  </g>`;
}

function backgroundSvg(slide, layout, clipId, gradId) {
  const img = imageSvg(slide, layout.image, clipId);
  if (slide.type === 'body') {
    return `<rect width="1080" height="1350" fill="${COLORS.cream}"/>
      <rect x="0" y="0" width="1080" height="610" fill="url(#${gradId})"/>
      ${img}
      <rect x="0" y="585" width="1080" height="56" fill="${COLORS.orange}"/>
      <path d="M0 602 L1080 542 L1080 642 L0 642 Z" fill="${COLORS.blue}" opacity=".96"/>
      <rect x="72" y="672" width="238" height="43" rx="21" fill="${COLORS.orange}"/>
      <text x="191" y="701" text-anchor="middle" fill="#111" font-family="Arial,sans-serif" font-size="22" font-weight="800">CRITICI DA BAR</text>`;
  }
  if (slide.type === 'question') {
    return `<rect width="1080" height="1350" fill="${COLORS.blue}"/>
      <circle cx="940" cy="140" r="245" fill="#064a61"/>
      <circle cx="130" cy="1200" r="280" fill="#064a61"/>
      <path d="M118 300 H962 Q1005 300 1005 343 V773 Q1005 816 962 816 H565 L442 942 L459 816 H118 Q75 816 75 773 V343 Q75 300 118 300 Z" fill="${COLORS.orange}" stroke="#1e25b8" stroke-width="12"/>`;
  }
  if (slide.type === 'final') {
    return `<rect width="1080" height="1350" fill="${COLORS.orange}"/>
      <path d="M0 0 H1080 V545 L0 710 Z" fill="${COLORS.blue}"/>
      <path d="M0 890 L1080 735 V1350 H0 Z" fill="#003b4e"/>
      <circle cx="930" cy="250" r="180" fill="#07475c" opacity=".75"/>`;
  }
  return `<rect width="1080" height="1350" fill="url(#${gradId})"/>
    ${img}
    <rect width="1080" height="1350" fill="#001c27" opacity="${slide.image.src ? '.38' : '.16'}"/>
    <path d="M-120 995 L1160 810 L1160 1430 L-120 1430 Z" fill="${COLORS.orange}"/>
    <path d="M-90 1115 L1160 930 L1160 1008 L-90 1193 Z" fill="#1f27b8" opacity=".96"/>
    <rect x="76" y="82" width="244" height="47" rx="24" fill="${COLORS.cream}"/>
    <text x="198" y="114" text-anchor="middle" fill="#111" font-family="Arial,sans-serif" font-size="22" font-weight="800">CRITICI DA BAR</text>`;
}

function buildSvg(slide, options = {}) {
  const unique = `s${slide.id || uid()}${options.suffix || ''}`.replace(/[^a-zA-Z0-9]/g, '');
  const clipId = `clip${unique}`;
  const gradId = `grad${unique}`;
  const layout = templateLayout(slide.type);
  return `<svg xmlns="${SVG_NS}" viewBox="0 0 1080 1350" width="1080" height="1350">
    <defs>
      <clipPath id="${clipId}"><rect x="${layout.image.x}" y="${layout.image.y}" width="${layout.image.w}" height="${layout.image.h}"/></clipPath>
      <linearGradient id="${gradId}" x1="0" y1="0" x2="1" y2="1"><stop offset="0" stop-color="${COLORS.blue}"/><stop offset="1" stop-color="#001b25"/></linearGradient>
    </defs>
    ${backgroundSvg(slide, layout, clipId, gradId)}
    ${textSvg('title', slide.title, layout.title)}
    ${textSvg('subtitle', slide.subtitle, layout.subtitle)}
    ${logoSvg(slide, layout.logo)}
  </svg>`;
}

function renderCanvasOnly() {
  const slide = currentSlide();
  canvas.innerHTML = buildSvg(slide, { suffix: 'main' }).replace(/^<svg[^>]*>|<\/svg>$/g, '');
  drawSelection();
}

function render() {
  renderCanvasOnly();
  renderFilmstrip();
  syncControls();
  $('slideCounter').textContent = `${currentIndex + 1} / ${project.slides.length}`;
  $('prevSlideBtn').disabled = currentIndex === 0;
  $('nextSlideBtn').disabled = currentIndex === project.slides.length - 1;
  $('deleteSlideBtn').disabled = project.slides.length === 1;
  $('moveLeftBtn').disabled = currentIndex === 0;
  $('moveRightBtn').disabled = currentIndex === project.slides.length - 1;
  updateUndoRedo();
}

function renderFilmstrip() {
  const strip = $('filmstrip');
  strip.innerHTML = '';
  project.slides.forEach((slide, index) => {
    const button = document.createElement('button');
    button.className = `thumb${index === currentIndex ? ' active' : ''}`;
    button.type = 'button';
    button.dataset.index = index;
    button.innerHTML = `${buildSvg(slide, { suffix: `t${index}` })}<span class="thumb-number">${index + 1}</span>`;
    button.addEventListener('click', () => { currentIndex = index; selected = 'title'; render(); });
    strip.appendChild(button);
  });
  requestAnimationFrame(() => strip.querySelector('.thumb.active')?.scrollIntoView({ behavior: 'smooth', block: 'nearest', inline: 'center' }));
}

function matrixPoint(matrix, x, y) {
  const p = new DOMPoint(x, y).matrixTransform(matrix);
  return { x: p.x, y: p.y };
}

function selectionBounds() {
  const target = canvas.querySelector(`[data-element="${selected}"]`);
  if (!target) return null;
  try {
    const box = target.getBBox();
    const m = target.getCTM();
    if (!m) return null;
    const pts = [
      matrixPoint(m, box.x, box.y), matrixPoint(m, box.x + box.width, box.y),
      matrixPoint(m, box.x, box.y + box.height), matrixPoint(m, box.x + box.width, box.y + box.height)
    ];
    const xs = pts.map(p => p.x), ys = pts.map(p => p.y);
    return { x: Math.min(...xs), y: Math.min(...ys), w: Math.max(...xs) - Math.min(...xs), h: Math.max(...ys) - Math.min(...ys) };
  } catch (error) { return null; }
}

function drawSelection() {
  canvas.querySelector('#selectionLayer')?.remove();
  const bounds = selectionBounds();
  if (!bounds) return;
  const layer = document.createElementNS(SVG_NS, 'g');
  layer.id = 'selectionLayer';
  layer.setAttribute('pointer-events', 'none');
  const pad = 18;
  const rect = document.createElementNS(SVG_NS, 'rect');
  rect.setAttribute('x', bounds.x - pad); rect.setAttribute('y', bounds.y - pad);
  rect.setAttribute('width', bounds.w + pad * 2); rect.setAttribute('height', bounds.h + pad * 2);
  rect.setAttribute('rx', '12'); rect.setAttribute('fill', 'none');
  rect.setAttribute('stroke', COLORS.orange); rect.setAttribute('stroke-width', '5'); rect.setAttribute('stroke-dasharray', '14 10');
  layer.appendChild(rect);
  const handle = document.createElementNS(SVG_NS, 'circle');
  handle.setAttribute('cx', bounds.x + bounds.w + pad); handle.setAttribute('cy', bounds.y + bounds.h + pad);
  handle.setAttribute('r', '35'); handle.setAttribute('fill', COLORS.orange); handle.setAttribute('stroke', COLORS.cream); handle.setAttribute('stroke-width', '7');
  handle.dataset.handle = 'scale';
  handle.setAttribute('pointer-events', 'all');
  layer.appendChild(handle);
  canvas.appendChild(layer);
}

function updateDomTransform(key) {
  const group = canvas.querySelector(`[data-element="${key}"]`);
  const element = currentSlide()[key];
  if (!group || !element) return;
  const cx = Number(group.dataset.cx), cy = Number(group.dataset.cy);
  group.setAttribute('transform', transformAttr(element, cx, cy));
  drawSelection();
}

function selectElement(key) {
  if (!['image','title','subtitle','logo'].includes(key)) return;
  selected = key;
  drawSelection();
  syncControls();
}

function syncControls() {
  const slide = currentSlide();
  $('titleInput').value = slide.title.text;
  $('subtitleInput').value = slide.subtitle.text;
  $('templateSelect').value = slide.type;
  $('projectNameInput').value = project.name || 'Nuovo carosello';
  document.querySelectorAll('.element-bar button').forEach(b => b.classList.toggle('active', b.dataset.select === selected));
  const isText = selected === 'title' || selected === 'subtitle';
  const element = currentElement();
  $('fontSelect').disabled = !isText;
  $('sizeRange').disabled = !isText;
  $('weightRange').disabled = !isText;
  $('widthRange').disabled = !isText;
  $('lineRange').disabled = !isText;
  $('colorInput').disabled = !isText;
  if (isText) {
    $('fontSelect').value = element.font;
    $('sizeRange').value = element.size;
    $('weightRange').value = element.weight;
    $('widthRange').value = element.width;
    $('lineRange').value = Math.round(element.lineHeight * 100);
    $('colorInput').value = element.color;
  }
  $('scaleRange').value = Math.round((element?.scale || 1) * 100);
  $('sizeOut').textContent = isText ? element.size : '—';
  $('weightOut').textContent = isText ? element.weight : '—';
  $('widthOut').textContent = isText ? `${element.width}%` : '—';
  $('lineOut').textContent = isText ? Number(element.lineHeight).toFixed(2) : '—';
  $('scaleOut').textContent = `${Math.round((element?.scale || 1) * 100)}%`;
}

function markDirty() {
  $('saveStatus').textContent = 'salvataggio…';
  clearTimeout(saveTimer);
  saveTimer = setTimeout(async () => {
    try {
      await dbPut('current', deepClone(project));
      $('saveStatus').textContent = 'salvato sul dispositivo';
    } catch (error) {
      console.error(error);
      $('saveStatus').textContent = 'errore salvataggio';
      showToast('Spazio locale non disponibile');
    }
  }, 300);
}

function imageAssetKey(src) {
  let hash = 2166136261;
  const step = Math.max(1, Math.floor(src.length / 2048));
  for (let i = 0; i < src.length; i += step) { hash ^= src.charCodeAt(i); hash = Math.imul(hash, 16777619); }
  return `asset:${src.length}:${(hash >>> 0).toString(36)}`;
}

function snapshot() {
  const compact = deepClone(project);
  compact.slides.forEach(slide => {
    const src = slide.image?.src;
    if (typeof src === 'string' && src.startsWith('data:')) {
      const key = imageAssetKey(src); historyImagePool.set(key, src); slide.image.src = key;
    }
  });
  return JSON.stringify(compact);
}

function projectFromSnapshot(value) {
  const restored = JSON.parse(value);
  restored.slides.forEach(slide => {
    const src = slide.image?.src;
    if (typeof src === 'string' && src.startsWith('asset:')) slide.image.src = historyImagePool.get(src) || '';
  });
  return restored;
}

function commitHistory() {
  const snap = snapshot();
  if (history[historyIndex] === snap) return;
  history = history.slice(0, historyIndex + 1);
  history.push(snap);
  if (history.length > 20) history.shift();
  historyIndex = history.length - 1;
  updateUndoRedo();
  markDirty();
}

function restoreHistory(index) {
  if (index < 0 || index >= history.length) return;
  historyIndex = index;
  project = projectFromSnapshot(history[historyIndex]);
  currentIndex = clamp(currentIndex, 0, project.slides.length - 1);
  render();
  markDirty();
}

function updateUndoRedo() {
  $('undoBtn').disabled = historyIndex <= 0;
  $('redoBtn').disabled = historyIndex >= history.length - 1;
}

function showToast(message) {
  const toast = $('toast');
  toast.textContent = message;
  toast.classList.add('show');
  clearTimeout(toastTimer);
  toastTimer = setTimeout(() => toast.classList.remove('show'), 2200);
}

function setTab(name) {
  activeTab = name;
  document.querySelectorAll('.tabs button').forEach(b => b.classList.toggle('active', b.dataset.tab === name));
  document.querySelectorAll('.tab-panel').forEach(p => p.classList.toggle('active', p.id === `tab-${name}`));
}

function screenToSvg(clientX, clientY) {
  const point = canvas.createSVGPoint();
  point.x = clientX; point.y = clientY;
  const matrix = canvas.getScreenCTM();
  return matrix ? point.matrixTransform(matrix.inverse()) : { x: 0, y: 0 };
}

function selectionCenterScreen() {
  const b = selectionBounds();
  if (!b) return { x: 0, y: 0 };
  const point = canvas.createSVGPoint();
  point.x = b.x + b.w / 2; point.y = b.y + b.h / 2;
  const m = canvas.getScreenCTM();
  return m ? point.matrixTransform(m) : { x: 0, y: 0 };
}

function pointerDistance(a, b) {
  return Math.hypot(a.x - b.x, a.y - b.y);
}

function resizeModeForSelection() {
  return selected === 'title' || selected === 'subtitle' ? 'fontSize' : 'scale';
}

function resizeElementFromRatio(element, mode, startValue, ratio) {
  if (mode === 'fontSize') {
    element.size = clamp(Math.round(startValue * ratio), 20, 220);
    renderCanvasOnly();
  } else {
    element.scale = clamp(startValue * ratio, 0.15, 5);
    updateDomTransform(selected);
  }
  syncControls();
}

function beginPinch() {
  const pts = [...pointers.values()];
  const element = currentElement();
  if (pts.length < 2 || !element) return;
  const mode = resizeModeForSelection();
  gesture = {
    type: 'pinch',
    mode,
    startDistance: pointerDistance(pts[0], pts[1]),
    startValue: mode === 'fontSize' ? element.size : (element.scale || 1)
  };
}

canvas.addEventListener('pointerdown', event => {
  event.preventDefault();
  canvas.setPointerCapture?.(event.pointerId);
  pointers.set(event.pointerId, { x: event.clientX, y: event.clientY });
  const elementTarget = event.target.closest?.('[data-element]');
  if (elementTarget?.dataset.element) selectElement(elementTarget.dataset.element);
  if (pointers.size === 2) {
    beginPinch();
    return;
  }
  if (!currentElement()) return;
  if (event.target.dataset.handle === 'scale') {
    const center = selectionCenterScreen();
    const mode = resizeModeForSelection();
    const element = currentElement();
    gesture = {
      type: 'handle', pointerId: event.pointerId, center, mode,
      startDistance: Math.max(1, Math.hypot(event.clientX - center.x, event.clientY - center.y)),
      startValue: mode === 'fontSize' ? element.size : (element.scale || 1)
    };
  } else {
    const start = screenToSvg(event.clientX, event.clientY);
    gesture = { type: 'drag', pointerId: event.pointerId, last: start };
  }
});

canvas.addEventListener('pointermove', event => {
  if (!pointers.has(event.pointerId)) return;
  event.preventDefault();
  pointers.set(event.pointerId, { x: event.clientX, y: event.clientY });
  const element = currentElement();
  if (!gesture || !element) return;
  if (pointers.size >= 2) {
    if (gesture.type !== 'pinch') beginPinch();
    const pts = [...pointers.values()];
    const distance = pointerDistance(pts[0], pts[1]);
    resizeElementFromRatio(element, gesture.mode, gesture.startValue, distance / Math.max(1, gesture.startDistance));
    return;
  }
  if (gesture.type === 'drag' && gesture.pointerId === event.pointerId) {
    const now = screenToSvg(event.clientX, event.clientY);
    element.dx += now.x - gesture.last.x;
    element.dy += now.y - gesture.last.y;
    gesture.last = now;
    const layout = templateLayout(currentSlide().type)[selected];
    if (layout) {
      const targetDx = W / 2 - layout.cx;
      const targetDy = H / 2 - layout.cy;
      if (Math.abs(element.dx - targetDx) < 14) element.dx = targetDx;
      if (Math.abs(element.dy - targetDy) < 14) element.dy = targetDy;
    }
    updateDomTransform(selected);
    syncControls();
  } else if (gesture.type === 'handle' && gesture.pointerId === event.pointerId) {
    const distance = Math.max(1, Math.hypot(event.clientX - gesture.center.x, event.clientY - gesture.center.y));
    resizeElementFromRatio(element, gesture.mode, gesture.startValue, distance / gesture.startDistance);
  }
});

function endPointer(event) {
  if (!pointers.has(event.pointerId)) return;
  pointers.delete(event.pointerId);
  try { canvas.releasePointerCapture?.(event.pointerId); } catch (_) {}
  if (pointers.size === 1 && gesture?.type === 'pinch') {
    const remaining = [...pointers.entries()][0];
    gesture = { type: 'drag', pointerId: remaining[0], last: screenToSvg(remaining[1].x, remaining[1].y) };
  } else if (pointers.size === 0) {
    gesture = null;
    commitHistory();
    renderFilmstrip();
  }
}
canvas.addEventListener('pointerup', endPointer);
canvas.addEventListener('pointercancel', endPointer);

