async function prepareImageFile(file) {
  const source = URL.createObjectURL(file);
  try {
    const image = await loadImage(source);
    const maxSide = 2400;
    const ratio = Math.min(1, maxSide / Math.max(image.naturalWidth, image.naturalHeight));
    const width = Math.max(1, Math.round(image.naturalWidth * ratio));
    const height = Math.max(1, Math.round(image.naturalHeight * ratio));
    const work = document.createElement('canvas'); work.width = width; work.height = height;
    const ctx = work.getContext('2d'); ctx.drawImage(image, 0, 0, width, height);
    const mime = file.type === 'image/png' && file.size < 1500000 ? 'image/png' : 'image/jpeg';
    const blob = await new Promise((resolve, reject) => work.toBlob(b => b ? resolve(b) : reject(new Error('Compressione fallita')), mime, 0.9));
    return await new Promise((resolve, reject) => {
      const reader = new FileReader(); reader.onload = () => resolve(reader.result); reader.onerror = reject; reader.readAsDataURL(blob);
    });
  } finally { URL.revokeObjectURL(source); }
}

