function textHeightLimit(type, key) {
  const limits = {
    cover: { title: 430, subtitle: 150 },
    body: { title: 190, subtitle: 260 },
    question: { title: 330, subtitle: 120 },
    final: { title: 390, subtitle: 120 }
  };
  return limits[type]?.[key] || 300;
}

function fitSelectedText() {
  if (selected !== 'title' && selected !== 'subtitle') {
    showToast('Seleziona prima un testo');
    return;
  }
  const style = currentElement();
  const layout = templateLayout(currentSlide().type)[selected];
  const maxHeight = textHeightLimit(currentSlide().type, selected);
  let nextSize = style.size;
  while (nextSize > 20) {
    const probe = { ...style, size: nextSize };
    const lines = wrapLines(probe.text, probe, layout.maxWidth);
    const height = Math.max(1, lines.length) * nextSize * probe.lineHeight;
    if (height <= maxHeight) break;
    nextSize -= 2;
  }
  if (nextSize === style.size) showToast('Il testo è già dentro l’area sicura');
  else {
    style.size = nextSize;
    renderCanvasOnly();
    syncControls();
    commitHistory();
    renderFilmstrip();
    showToast(`Dimensione adattata a ${nextSize}`);
  }
}

