function slug(value) {
  return String(value || 'carosello').normalize('NFD').replace(/[\u0300-\u036f]/g, '').toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '').slice(0, 70) || 'carosello';
}

function downloadBlob(blob, filename) {
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a'); a.href = url; a.download = filename;
  document.body.appendChild(a); a.click(); a.remove();
  setTimeout(() => URL.revokeObjectURL(url), 1500);
}

async function loadImage(src) {
  return new Promise((resolve, reject) => {
    const image = new Image(); image.onload = () => resolve(image); image.onerror = reject; image.src = src;
  });
}

function roundedRectPath(ctx, x, y, w, h, r) {
  ctx.beginPath(); ctx.roundRect(x, y, w, h, r);
}

function drawCoverImage(ctx, img, rect, transform) {
  ctx.save();
  ctx.beginPath(); ctx.rect(rect.x, rect.y, rect.w, rect.h); ctx.clip();
  ctx.translate(transform.dx || 0, transform.dy || 0);
  ctx.translate(rect.cx, rect.cy); ctx.scale(transform.scale || 1, transform.scale || 1); ctx.translate(-rect.cx, -rect.cy);
  const imageRatio = img.naturalWidth / img.naturalHeight;
  const rectRatio = rect.w / rect.h;
  let dw, dh;
  if (imageRatio > rectRatio) { dh = rect.h; dw = dh * imageRatio; }
  else { dw = rect.w; dh = dw / imageRatio; }
  ctx.drawImage(img, rect.x + (rect.w - dw) / 2, rect.y + (rect.h - dh) / 2, dw, dh);
  ctx.restore();
}

function fillGradient(ctx, x, y, w, h) {
  const grad = ctx.createLinearGradient(x, y, x + w, y + h);
  grad.addColorStop(0, COLORS.blue); grad.addColorStop(1, '#001b25');
  ctx.fillStyle = grad; ctx.fillRect(x, y, w, h);
}

async function drawBackgroundCanvas(ctx, slide, layout) {
  if (slide.type === 'body') {
    ctx.fillStyle = COLORS.cream; ctx.fillRect(0, 0, W, H); fillGradient(ctx, 0, 0, W, 610);
    if (slide.image.src) drawCoverImage(ctx, await loadImage(slide.image.src), layout.image, slide.image);
    ctx.fillStyle = COLORS.orange; ctx.fillRect(0, 585, W, 56);
    ctx.fillStyle = COLORS.blue; ctx.beginPath(); ctx.moveTo(0,602); ctx.lineTo(1080,542); ctx.lineTo(1080,642); ctx.lineTo(0,642); ctx.closePath(); ctx.fill();
    ctx.fillStyle = COLORS.orange; roundedRectPath(ctx,72,672,238,43,21); ctx.fill();
    ctx.fillStyle = '#111'; ctx.font = '800 22px Arial'; ctx.textAlign = 'center'; ctx.fillText('CRITICI DA BAR',191,701);
    return;
  }
  if (slide.type === 'question') {
    ctx.fillStyle = COLORS.blue; ctx.fillRect(0,0,W,H);
    ctx.fillStyle = '#064a61'; ctx.beginPath(); ctx.arc(940,140,245,0,Math.PI*2); ctx.fill(); ctx.beginPath(); ctx.arc(130,1200,280,0,Math.PI*2); ctx.fill();
    ctx.fillStyle = COLORS.orange; ctx.strokeStyle = '#1e25b8'; ctx.lineWidth = 12;
    const p = new Path2D('M118 300 H962 Q1005 300 1005 343 V773 Q1005 816 962 816 H565 L442 942 L459 816 H118 Q75 816 75 773 V343 Q75 300 118 300 Z'); ctx.fill(p); ctx.stroke(p); return;
  }
  if (slide.type === 'final') {
    ctx.fillStyle = COLORS.orange; ctx.fillRect(0,0,W,H);
    ctx.fillStyle = COLORS.blue; ctx.beginPath(); ctx.moveTo(0,0); ctx.lineTo(1080,0); ctx.lineTo(1080,545); ctx.lineTo(0,710); ctx.closePath(); ctx.fill();
    ctx.fillStyle = '#003b4e'; ctx.beginPath(); ctx.moveTo(0,890); ctx.lineTo(1080,735); ctx.lineTo(1080,1350); ctx.lineTo(0,1350); ctx.closePath(); ctx.fill();
    ctx.globalAlpha=.75; ctx.fillStyle='#07475c'; ctx.beginPath();ctx.arc(930,250,180,0,Math.PI*2);ctx.fill();ctx.globalAlpha=1; return;
  }
  fillGradient(ctx,0,0,W,H);
  if (slide.image.src) drawCoverImage(ctx, await loadImage(slide.image.src), layout.image, slide.image);
  ctx.fillStyle = 'rgba(0,28,39,' + (slide.image.src ? '.38' : '.16') + ')'; ctx.fillRect(0,0,W,H);
  ctx.fillStyle = COLORS.orange; ctx.beginPath();ctx.moveTo(-120,995);ctx.lineTo(1160,810);ctx.lineTo(1160,1430);ctx.lineTo(-120,1430);ctx.closePath();ctx.fill();
  ctx.fillStyle='#1f27b8';ctx.beginPath();ctx.moveTo(-90,1115);ctx.lineTo(1160,930);ctx.lineTo(1160,1008);ctx.lineTo(-90,1193);ctx.closePath();ctx.fill();
  ctx.fillStyle=COLORS.cream;roundedRectPath(ctx,76,82,244,47,24);ctx.fill();ctx.fillStyle='#111';ctx.font='800 22px Arial';ctx.textAlign='center';ctx.fillText('CRITICI DA BAR',198,114);
}

function drawTextCanvas(ctx, style, layout) {
  const lines = wrapLines(style.text, style, layout.maxWidth);
  ctx.save();
  ctx.translate(style.dx || 0, style.dy || 0);
  ctx.translate(layout.cx, layout.cy); ctx.scale(style.scale || 1, style.scale || 1); ctx.translate(-layout.cx, -layout.cy);
  ctx.translate(layout.x, 0); ctx.scale((style.width || 100) / 100, 1); ctx.translate(-layout.x, 0);
  ctx.font = `${style.weight || 400} ${style.size || 60}px "${style.font || 'Anybody'}"`;
  ctx.fillStyle = style.color; ctx.textAlign = layout.align; ctx.textBaseline = 'alphabetic';
  lines.forEach((line, index) => ctx.fillText(line, layout.x, layout.y + index * style.size * style.lineHeight));
  ctx.restore();
}

async function renderPngBlob(slide) {
  await Promise.all(['Anybody','Archivo','Saira'].map(font => document.fonts?.load(`800 90px "${font}"`).catch(() => null)) || []);
  const out = document.createElement('canvas'); out.width = W; out.height = H;
  const ctx = out.getContext('2d'); const layout = templateLayout(slide.type);
  await drawBackgroundCanvas(ctx, slide, layout);
  drawTextCanvas(ctx, slide.title, layout.title); drawTextCanvas(ctx, slide.subtitle, layout.subtitle);
  const logo = await loadImage(LOGO_DATA);
  ctx.save(); ctx.translate(slide.logo.dx||0,slide.logo.dy||0); ctx.translate(layout.logo.cx,layout.logo.cy);ctx.scale(slide.logo.scale||1,slide.logo.scale||1);ctx.translate(-layout.logo.cx,-layout.logo.cy);ctx.drawImage(logo,layout.logo.x,layout.logo.y,layout.logo.w,layout.logo.h);ctx.restore();
  return new Promise((resolve, reject) => out.toBlob(blob => blob ? resolve(blob) : reject(new Error('Impossibile creare il PNG')), 'image/png'));
}

